  ('locality-6f0ba476-moex-00505', 'locality-6f0ba476', 'locality-6f0ba476-moex-110-9b7ab1bb', 'sub-locality-6f0ba476-02', NULL, 'single_choice', '下列關於消滅時效中斷及不完成之敘述，何者錯誤？', '["消滅時效中斷事由終止後，時效重行起算", "消滅時效因起訴而中斷", "消滅時效中斷事由僅有對人之相對效力", "消滅時效不完成事由僅有對人之相對效力"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:05+00:00", "source_pdf_sha1": "a4b613a63dd0", "answer_pdf_sha1": "7542e7107b70", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "312", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00506', 'locality-6f0ba476', 'locality-6f0ba476-moex-110-9b7ab1bb', 'sub-locality-6f0ba476-02', NULL, 'single_choice', '依民法規定，下列關於法人董事代表權之敘述，何者正確？', '["社團定有代表權之董事者，應於設立時登記之，若未經登記者，僅不得以其對抗善意第三人", "社團法人總會決議對董事代表權所加之限制，不得對抗善意第三人", "董事有數人者，法人事務之執行，除章程另有規定外，取決於全體董事三分之二同意", "董事無代表權者，其代表法人所為之行為，對法人當然不發生效力"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:05+00:00", "source_pdf_sha1": "a4b613a63dd0", "answer_pdf_sha1": "7542e7107b70", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "312", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00507', 'locality-6f0ba476', 'locality-6f0ba476-moex-110-9b7ab1bb', 'sub-locality-6f0ba476-02', NULL, 'single_choice', '甲為有機小農，有萬坪農地一筆，其上蓋有農舍一棟，並種植千株梨樹與樟樹一棵，在樟樹下已 長期蓋有一座足以遮風避雨之涼亭，另又臨時搭設可移動之工作帳篷一頂。下列敘述，何者錯誤？', '["工作帳篷為獨立之動產", "樟樹為獨立之不動產", "農舍為獨立之不動產", "涼亭為獨立之不動產"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:05+00:00", "source_pdf_sha1": "a4b613a63dd0", "answer_pdf_sha1": "7542e7107b70", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "312", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00508', 'locality-6f0ba476', 'locality-6f0ba476-moex-110-9b7ab1bb', 'sub-locality-6f0ba476-02', NULL, 'single_choice', '下列關於民法期間起算之敘述，何者錯誤？', '["以時定期間者，其始時不算入", "以星期定期間者，其始日不算入", "以日定期間者，其始日不算入", "以年定期間者，其始日不算入"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:05+00:00", "source_pdf_sha1": "a4b613a63dd0", "answer_pdf_sha1": "7542e7107b70", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "312", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00509', 'locality-6f0ba476', 'locality-6f0ba476-moex-110-9b7ab1bb', 'sub-locality-6f0ba476-02', NULL, 'single_choice', '下列關於定金之敘述，何者正確？', '["定金契約為不要物契約", "定金契約之性質為從契約", "訂約當事人之一方，由他方受有定金時，視為其契約成立", "契約履行時，定金應返還，不得作為給付之一部"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:05+00:00", "source_pdf_sha1": "a4b613a63dd0", "answer_pdf_sha1": "7542e7107b70", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "312", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00510', 'locality-6f0ba476', 'locality-6f0ba476-moex-110-9b7ab1bb', 'sub-locality-6f0ba476-02', NULL, 'single_choice', '甲對乙負有新臺幣 10 萬元的債務，丙因想追求甲，而欲承擔甲對乙的債務。下列敘述，何者正 確？', '["丙得與甲訂立契約承擔其債務，其債務於契約成立時，移轉於丙", "丙與乙訂立契約承擔甲之債務者，非經甲承認，對於甲不生效力", "丙承擔甲的債務後，甲因其法律關係所得對抗乙之事由，丙亦得以之對抗乙", "丙因其承擔甲債務之法律關係所得對抗甲之事由，得以之對抗乙"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:05+00:00", "source_pdf_sha1": "a4b613a63dd0", "answer_pdf_sha1": "7542e7107b70", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "312", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00511', 'locality-6f0ba476', 'locality-6f0ba476-moex-110-9b7ab1bb', 'sub-locality-6f0ba476-02', NULL, 'single_choice', '下列關於違約金之敘述，何者錯誤？', '["違約金，除非當事人有特別約定，否則推定為「因不履行而生損害之賠償總額」", "同屬於契約確保之手段，「定金」是要物契約，「違約金」是不要物契約", "約定之違約金過高，法院得酌減之", "若當事人所約定係懲罰性違約金，則債務人之債務不履行有損害發生時，仍須負損害賠償責任"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:05+00:00", "source_pdf_sha1": "a4b613a63dd0", "answer_pdf_sha1": "7542e7107b70", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "312", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00512', 'locality-6f0ba476', 'locality-6f0ba476-moex-110-9b7ab1bb', 'sub-locality-6f0ba476-02', NULL, 'single_choice', '甲欠乙新臺幣（下同）20萬元，約定同年3月1日清償借款，期限屆至，甲卻未返還20萬元給 乙。下列敘述，何者正確？', '["縱使乙能證明有其他損害者，亦不得請求賠償", "縱使遲延後之給付對乙有利益者，乙仍得請求替補賠償", "甲遲延給付20萬元欠款，乙至少得對甲請求依照法定利率或約定利率計算之遲延利息", "若甲身無分文，則成立給付不能 31570"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:05+00:00", "source_pdf_sha1": "a4b613a63dd0", "answer_pdf_sha1": "7542e7107b70", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "312", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00513', 'locality-6f0ba476', 'locality-6f0ba476-moex-110-9b7ab1bb', 'sub-locality-6f0ba476-02', NULL, 'single_choice', '下列關於分期付價買賣之敘述，何者正確？', '["分期付價買賣之標的，民法並無限制，故動產、不動產或權利均得為之", "分期付價之買賣，民法規定如買受人解除契約時，出賣人得扣留其所受領價金，惟其扣留之數 額，不得超過標的物全部價金五分之一", "分期付價之買賣，民法規定如出賣人解除契約時，出賣人得扣留其所受領價金，惟其扣留之數 額，不得超過標的物全部價金五分之一", "分期付價之買賣，民法規定如買受人遲付之價額已達全部價金十分之一，出賣人即得請求支付 全部價金"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:05+00:00", "source_pdf_sha1": "a4b613a63dd0", "answer_pdf_sha1": "7542e7107b70", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "312", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00514', 'locality-6f0ba476', 'locality-6f0ba476-moex-110-9b7ab1bb', 'sub-locality-6f0ba476-02', NULL, 'single_choice', '甲購買新電腦一部，而將現用之電腦送給乙。下列敘述，何者正確？', '["甲將電腦所有權移轉乙後，如事後後悔，仍得隨時撤銷契約", "甲在騎機車送電腦給乙的路途中，被酒駕者撞倒，致電腦全毀，甲應負給付不能之責任", "電腦交付後，乙發現有一個USB插孔是故障的，甲有修補的義務", "乙在受領電腦後，因細故跟甲發生爭吵，把甲打到腦震盪，甲得撤銷贈與"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:05+00:00", "source_pdf_sha1": "a4b613a63dd0", "answer_pdf_sha1": "7542e7107b70", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "312", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL)
